<?php/** * Created by PhpStorm. * User: Cyril * Date: 21/03/2016 * Time: 18:44 */class Paypal{    private $user ='contact_api1.managy.fr';    private $password = '6MRR4WSCGTD3RJHE';    private $signature = 'AFcWxV21C7fd0v3bYYYRCpSSRl31AQ5Sgh368BwUijSNgOHBPbaaRlc4';    private $version = '74.0';    private $api_url = 'https://api-3T.sandbox.paypal.com/nvp';    public $errors = Array();    public function __construct($prod = true)    {        if($prod)            $this->api_url = 'https://api-3t.paypal.com/nvp';        else            $this->api_url = 'https://api-3T.sandbox.paypal.com/nvp';    }    public function request($method, $params)    {        $params = array_merge($params, Array(            'METHOD' => $method,            'VERSION' => $this->version,            'USER' => $this->user,            'SIGNATURE' => $this->signature,            'PWD' => $this->password        ));        $parametres = http_build_query($params);        $curl = curl_init();        curl_setopt_array($curl, array(            CURLOPT_URL => $this->api_url,            CURLOPT_POST => 1,            CURLOPT_POSTFIELDS => $parametres,            CURLOPT_RETURNTRANSFER => 1,            CURLOPT_SSL_VERIFYPEER => true,            CURLOPT_SSL_VERIFYHOST => true,            CURLOPT_VERBOSE => 1        ));        $response = curl_exec($curl);        $responseArray = Array();        parse_str($response, $responseArray);        if(curl_errno($curl))        {            $this->errors = curl_error($curl);            curl_close($curl);            return false;        }        else        {            if($responseArray['ACK'] == 'Success')            {                curl_close($curl);                return $responseArray;            }            else            {                $this->errors = $responseArray;                curl_close($curl);                return false;            }        }    }}